#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main(){
    int Q; if(scanf("%d", &Q)!=1) return 0;
    while(Q--){
        int n,m; scanf("%d %d", &n, &m);
        char *S = (char*)malloc((n+5)*sizeof(char));
        char *T = (char*)malloc((m+5)*sizeof(char));
        scanf("%s", S);
        scanf("%s", T);
        int need[128]={0}, have[128]={0};
        int required=0;
        for(int i=0;i<m;i++){
            unsigned char c = T[i];
            if(need[c]==0) required++;
            need[c]++;
        }
        int formed=0, left=0, bestLen=n+1, bestStart=0;
        for(int right=0; right<n; right++){
            unsigned char c = S[right];
            have[c]++;
            if(have[c]==need[c] && need[c]>0) formed++;
            while(formed==required && left<=right){
                int curLen = right-left+1;
                if(curLen<bestLen){
                    bestLen=curLen; bestStart=left;
                }
                unsigned char lc = S[left];
                if(have[lc]==need[lc] && need[lc]>0) formed--;
                have[lc]--;
                left++;
            }
        }
        if(bestLen==n+1){
            printf("IMPOSSIBLE\n");
        }else{
            printf("%d\n", bestLen);
            for(int i=0;i<bestLen;i++) putchar(S[bestStart+i]);
            putchar('\n');
        }
        free(S); free(T);
    }
    return 0;
}

