    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int Q = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (Q-- > 0) {
            st = new StringTokenizer(br.readLine());
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            String S = br.readLine();
            String T = br.readLine();
            int[] need = new int[128];
            int[] have = new int[128];
            int required = 0;
            for (int i = 0; i < T.length(); i++) {
                int c = T.charAt(i);
                if (need[c] == 0) required++;
                need[c]++;
            }
            int formed = 0, left = 0, bestLen = n + 1, bestStart = 0;
            for (int right = 0; right < S.length(); right++) {
                int c = S.charAt(right);
                have[c]++;
                if (have[c] == need[c] && need[c] > 0) formed++;
                while (formed == required && left <= right) {
                    int curLen = right - left + 1;
                    if (curLen < bestLen) {
                        bestLen = curLen;
                        bestStart = left;
                    }
                    int lc = S.charAt(left);
                    if (have[lc] == need[lc] && need[lc] > 0) formed--;
                    have[lc]--;
                    left++;
                }
            }
            if (bestLen == n + 1) {
                out.append("IMPOSSIBLE\n");
            } else {
                out.append(bestLen).append('\n').append(S.substring(bestStart, bestStart + bestLen)).append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

