const Q = parseInt(input[ptr++]);
let output = [];
for (let tc = 0; tc < Q; tc++) {
  const [nStr, mStr] = input[ptr++].trim().split(/\s+/);
  const n = parseInt(nStr), m = parseInt(mStr);
  const S = input[ptr++] || '';
  const T = input[ptr++] || '';
  const need = new Array(128).fill(0);
  const have = new Array(128).fill(0);
  let required = 0;
  for (let ch of T) {
    const c = ch.charCodeAt(0);
    if (need[c] === 0) required++;
    need[c]++;
  }
  let formed = 0, left = 0, bestLen = n + 1, bestStart = 0;
  for (let right = 0; right < S.length; right++) {
    const c = S.charCodeAt(right);
    have[c]++;
    if (have[c] === need[c] && need[c] > 0) formed++;
    while (formed === required && left <= right) {
      const curLen = right - left + 1;
